    /**
     * Build the WHERE clause and parameters dynamically based on filters.
     */
    private function buildWhereClause(array $filters): array
    {
        $conditions = [];
        $params = [];

        // Date range filter
        if (!empty($filters['date_from'])) {
            $conditions[] = "o.created_at >= :date_from";
            $params[':date_from'] = $filters['date_from'] . ' 00:00:00';
        }

        if (!empty($filters['date_to'])) {
            $conditions[] = "o.created_at <= :date_to";
            $params[':date_to'] = $filters['date_to'] . ' 23:59:59';
        }

        // Status filter (supports multiple values via IN clause)
        if (!empty($filters['status'])) {
            $statusPlaceholders = [];
            foreach ($filters['status'] as $index => $status) {
                $placeholder = ":status_{$index}";
                $statusPlaceholders[] = $placeholder;
                $params[$placeholder] = $status;
            }
            $conditions[] = "o.status IN (" . implode(', ', $statusPlaceholders) . ")";
        }

        // Category filter (supports multiple values via IN clause)
        if (!empty($filters['category'])) {
            $categoryPlaceholders = [];
            foreach ($filters['category'] as $index => $category) {
                $placeholder = ":category_{$index}";
                $categoryPlaceholders[] = $placeholder;
                $params[$placeholder] = $category;
            }
            $conditions[] = "o.category IN (" . implode(', ', $categoryPlaceholders) . ")";
        }

        // Search keyword filter
        if (!empty($filters['search'])) {
            $conditions[] = "(o.title LIKE :search OR o.description LIKE :search)";
            $params[':search'] = '%' . $filters['search'] . '%';
        }

        $whereClause = '';
        if (!empty($conditions)) {
            $whereClause = 'WHERE ' . implode(' AND ', $conditions);
        }

        return [$whereClause, $params];
    }

    /**
     * Build ORDER BY clause.
     */
    private function buildOrderByClause(array $filters): string
    {
        $sortBy = $filters['sort_by'] ?? 'created_at';
        $sortOrder = $filters['sort_order'] ?? 'DESC';

        // Whitelist the column name to prevent SQL injection (already validated in sanitize)
        $allowedSortColumns = ['id', 'title', 'status', 'category', 'created_at', 'updated_at', 'amount', 'quantity'];
        if (!in_array($sortBy, $allowedSortColumns, true)) {
            $sortBy = 'created_at';
        }

        return "ORDER BY o.{$sortBy} {$sortOrder}";
    }

    /**
     * Build LIMIT/OFFSET clause for pagination.
     */
    private function buildPaginationClause(array $filters): array
    {
        $page = $filters['page'] ?? 1;
        $perPage = $filters['per_page'] ?? 25;
        $offset = ($page - 1) * $perPage;

        return [
            'clause' => "LIMIT :limit OFFSET :offset",
            'params' => [
                ':limit' => (int)$perPage,
                ':offset' => (int)$offset,
            ],
        ];
    }

    /**
     * Generate a detailed report with all records matching the filters.
     */
    private function generateDetailedReport(array $filters): array
    {
        [$whereClause, $params] = $this->buildWhereClause($filters);
        $orderByClause = $this->buildOrderByClause($filters);
        $pagination = $this->buildPaginationClause($filters);

        // Count total records
        $countSql = "SELECT COUNT(*) AS total FROM orders o {$whereClause}";
        $countStmt = $this->pdo->prepare($countSql);
        $countStmt->execute($params);
        $totalRecords = (int)$countStmt->fetchColumn();

        // Fetch paginated data
        $dataSql = "
            SELECT 
                o.id,
                o.title,
                o.description,
                o.status,
                o.category,
                o.amount,
                o.quantity,
                o.created_at,
                o.updated_at
            FROM orders o
            {$whereClause}
            {$orderByClause}
            {$pagination['clause']}
        ";

        $dataStmt = $this->pdo->prepare($dataSql);

        // Bind all WHERE params
        foreach ($params as $key => $value) {
            $dataStmt->bindValue($key, $value);
        }

        // Bind pagination params as integers
        $dataStmt->bindValue(':limit', $pagination['params'][':limit'], PDO::PARAM_INT);
        $dataStmt->bindValue(':offset', $pagination['params'][':offset'], PDO::PARAM_INT);

        $dataStmt->execute();
        $records = $dataStmt->fetchAll();

        $perPage = $filters['per_page'] ?? 25;
        $currentPage = $filters['page'] ?? 1;

        return [
            'report_type' => 'detailed',
